#[derive(Debug)]
struct AuthUser(Claims);

#[rocket::async_trait]
impl<'r> FromRequest<'r> for AuthUser {
    type Error = ApiError;
    async fn from_request(req: &'r Request<'_>) -> request::Outcome<Self, Self::Error> {
        let token = req.headers().get_one("Authorization")
            .and_then(|h| h.strip_prefix("Bearer "));
        match token {
            Some(t) => match verify_token(t) {
                Ok(claims) => Outcome::Success(AuthUser(claims)),
                Err(_) => Outcome::Error((Status::Unauthorized, ApiError::Unauthorized)),
            },
            None => Outcome::Error((Status::Unauthorized, ApiError::Unauthorized)),
        }
    }
}

#[get("/protected")]
async fn protected(user: AuthUser) -> Json<Profile> { }

