#[catch(404)]
fn not_found() -> Json<ErrorBody> {
    Json(ErrorBody { error: "not found".into() })
}

#[catch(500)]
fn internal() -> Json<ErrorBody> {
    Json(ErrorBody { error: "internal error".into() })
}

#[launch]
fn rocket() -> _ {
    rocket::build()
        .register("/", catchers![not_found, internal])
}

use rocket::local::asynchronous::Client;

#[tokio::test]
async fn test_get_user() {
    let client = Client::tracked(rocket()).await.unwrap();
    let response = client.get("/api/users/1").dispatch().await;
    assert_eq!(response.status(), Status::Ok);
    let user: User = response.into_json().await.unwrap();
    assert_eq!(user.id, 1);
}

